Class User.DataValidator Extends %RegisteredObject
{
    ClassMethod Validate(data As %String, type As %String) As %Status
    {
        If (data = "") Quit $$$ERROR($$$GeneralError, "Empty data")
        If (type = "") Quit $$$ERROR($$$GeneralError, "Empty type")
        Quit $$$OK
    }
}

Class User.DataProcessor Extends %RegisteredObject
{
    ClassMethod Process(data As %String, type As %String) As %Status
    {
        Set sc = ##class(User.DataValidator).Validate(data, type)
        If $$$ISERR(sc) Quit sc
        Quit $$$OK
    }
}

