Class User.TestDataProcessor Extends %RegisteredObject
{
    ClassMethod TestProcess()
    {
        // Test expects 'type' validation to be implemented
        Set sc = ##class(User.DataProcessor).Process("valid data", "")
        // If type is empty, it should now fail after the fix
        If $$$ISOK(sc) Throw ##class(%Exception.General).%New("Should have failed for empty type")

        Set sc2 = ##class(User.DataProcessor).Process("valid data", "some type")
        If $$$ISERR(sc2) Throw ##class(%Exception.General).%New("Should have passed for valid type: "_sc2)
    }
}
